  1	import * as React from 'react';
  2	import {
  3	  AccessKeyStatus,
  4	  IAM_BASE_ROUTE,
  5	  IAM_USERS_BOOKMARKS_USER_SETTINGS_KEY,
  6	} from '@odf/core/constants/s3-iam';
  7	import { DASH, useUserSettingsLocalStorage } from '@odf/shared';
  8	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  9	import { IamCommands } from '@odf/shared/iam';
 10	import { CommonModalProps } from '@odf/shared/modals';
 11	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 12	import * as _ from 'lodash-es';
 13	import { Trans } from 'react-i18next';
 14	import { TFunction } from 'react-i18next';
 15	import { useNavigate } from 'react-router-dom-v5-compat';
 16	import {
 17	  Modal,
 18	  Button,
 19	  ModalVariant,
 20	  Text,
 21	  TextInput,
 22	  TextInputTypes,
 23	  FormGroup,
 24	  Alert,
 25	  AlertVariant,
 26	  ButtonVariant,
 27	  Spinner,
 28	  FlexItem,
 29	  List,
 30	  ListItem,
 31	  AlertActionLink,
 32	} from '@patternfly/react-core';
 33	import { Table, Thead, Tr, Th, Tbody, Td } from '@patternfly/react-table';
 34	import { useUserAccessKeys } from '../../components/s3-iam/hooks/useUserAccessKeys';
 35	import { useUserDetails } from '../../components/s3-iam/hooks/useUserDetails';
 36	import { cleanupAllPolicies } from '../../utils/s3-iam';
 37	
 38	type DeleteIamUserModalProps = {
 39	  userName: string;
 40	  iamClient: IamCommands;
 41	  refreshTokens: () => void;
 42	};
 43	
 44	const getTextInputLabel = (t: TFunction) => (
 45	  <Trans t={t as any}>
 46	    <b>
 47	      To confirm deletion, type <i>{{ delete: 'delete' }}</i>:
 48	    </b>
 49	  </Trans>
 50	);
 51	
 52	const getDescription = (t: TFunction) => (
 53	  <div className="text-muted">
 54	    {t(
 55	      'Delete the IAM user permanently? All user data, access keys, secret keys and inline policies related to this user will also be deleted'
 56	    )}
 57	  </div>
 58	);
 59	
 60	/**
 61	 * Delete IAM User Modal, delete the Access Keys before deletion
 62	 * @param userName @param iamClient @param refreshTokens
 63	 */
 64	export const DeleteIamUserModal: React.FC<
 65	  CommonModalProps<DeleteIamUserModalProps>
 66	> = ({
 67	  closeModal,
 68	  isOpen,
 69	  extraProps: { userName, iamClient, refreshTokens },
 70	}) => {
 71	  const { t } = useCustomTranslation();
 72	  const [deleteText, setDeleteText] = React.useState<string>('');
 73	  const [inProgress, setInProgress] = React.useState<boolean>(false);
 74	  const [error, setError] = React.useState<Error>();
 75	  const [deleteSuccess, setDeleteSuccess] = React.useState(false);
 76	
 77	  const navigate = useNavigate();
 78	
 79	  // Fetch user details
 80	  const {
 81	    userDetails,
 82	    isLoading: isLoadingUser,
 83	    error: userError,
 84	  } = useUserDetails(userName, iamClient);
 85	
 86	  // Fetch user access keys
 87	  const {
 88	    iamAccessKeys,
 89	    isLoading: isLoadingAccessKeys,
 90	    error: accessKeysError,
 91	  } = useUserAccessKeys(userName, iamClient);
 92	
 93	  const hasAccessKeys = iamAccessKeys.length > 0;
 94	
 95	  const isChecking = isLoadingUser || isLoadingAccessKeys;
 96	  const fetchError = userError || accessKeysError;
 97	
 98	  const creationDate = userDetails?.CreateDate
 99	    ? new Date(userDetails.CreateDate).toLocaleDateString()
100	    : DASH;
101	
102	  const lastUsed = userDetails?.PasswordLastUsed
103	    ? new Date(userDetails.PasswordLastUsed).toLocaleDateString()
104	    : DASH;
105	
106	  const [, setFavorites] = useUserSettingsLocalStorage<string[]>(
107	    IAM_USERS_BOOKMARKS_USER_SETTINGS_KEY,
108	    true,
109	    []
110	  );
111	
112	  const onDelete = async (event) => {
113	    event.preventDefault();
114	    setInProgress(true);
115	
116	    try {
117	      // Clean up all inline policies before deleting user
118	      await cleanupAllPolicies(iamClient, userName);
119	
120	      await iamClient.deleteIamUser({
121	        UserName: userName,
122	      });
123	
124	      setInProgress(false);
125	      closeModal();
126	      setFavorites((oldFavorites) =>
127	        oldFavorites.filter((user) => user !== userName)
128	      );
129	      refreshTokens();
130	      navigate(IAM_BASE_ROUTE);
131	    } catch (err) {
132	      setError(err as Error);
133	    } finally {
134	      setInProgress(false);
135	    }
136	  };
137	
138	  const onDeleteAccessKeys = async (event: React.FormEvent) => {
139	    event.preventDefault();
140	    setInProgress(true);
141	
142	    try {
143	      const accessKeys = iamAccessKeys ?? [];
144	      if (accessKeys.length === 0) {
145	        setDeleteSuccess(true);
146	        return;
147	      }
148	
149	      const deactivateAccessKeysPromises = accessKeys
150	        .filter((key) => key.Status === AccessKeyStatus.ACTIVE)
151	        .map((key) =>
152	          iamClient.updateAccessKey({
153	            AccessKeyId: key.AccessKeyId,
154	            Status: AccessKeyStatus.INACTIVE,
155	            UserName: userName,
156	          })
157	        );
158	
159	      if (deactivateAccessKeysPromises.length > 0) {
160	        await Promise.all(deactivateAccessKeysPromises);
161	      }
162	
163	      const deleteAccessKeysPromises = accessKeys.map((key) =>
164	        iamClient.deleteAccessKey({
165	          UserName: key.UserName,
166	          AccessKeyId: key.AccessKeyId,
167	        })
168	      );
169	
170	      await Promise.all(deleteAccessKeysPromises);
171	
172	      setDeleteSuccess(true);
173	    } catch (err) {
174	      setError(err as Error);
175	    } finally {
176	      setInProgress(false);
177	    }
178	  };
179	  return (
180	    <Modal
181	      title={t('Delete user?')}
182	      titleIconVariant="danger"
183	      isOpen={isOpen}
184	      onClose={closeModal}
185	      description={getDescription(t)}
186	      variant={ModalVariant.medium}
187	      actions={[
188	        <ButtonBar
189	          key="actions"
190	          inProgress={inProgress}
191	          errorMessage={error?.message || fetchError?.message}
192	        >
193	          <span>
194	            <Button
195	              className="pf-v6-u-mr-xs"
196	              variant={ButtonVariant.danger}
197	              isLoading={inProgress}
198	              isDisabled={deleteText !== t('delete') || inProgress}
199	              onClick={onDelete}
200	            >
201	              {t('Delete user')}
202	            </Button>
203	            <Button
204	              variant={ButtonVariant.link}
205	              onClick={closeModal}
206	              className="pf-v6-u-ml-xs"
207	            >
208	              {t('Cancel')}
209	            </Button>
210	          </span>
211	        </ButtonBar>,
212	      ]}
213	    >
214	      <Table variant="compact" borders={true} className="pf-v6-u-mb-md">
215	        <Thead>
216	          <Tr>
217	            <Th>{t('User name')}</Th>
218	            <Th>{t('Creation date')}</Th>
219	            <Th>{t('Last activity')}</Th>
220	          </Tr>
221	        </Thead>
222	        <Tbody>
223	          <Tr>
224	            <Td dataLabel={t('User name')}>{userName || DASH}</Td>
225	            <Td dataLabel={t('Creation date')}>{creationDate}</Td>
226	            <Td dataLabel={t('Last activity')}>{lastUsed}</Td>
227	          </Tr>
228	        </Tbody>
229	      </Table>
230	      {isChecking ? (
231	        <Spinner size="md" className="pf-v6-u-mb-md" />
232	      ) : (
233	        hasAccessKeys &&
234	        !deleteSuccess && (
235	          <FlexItem>
236	            <Alert
237	              variant="warning"
238	              isInline
239	              title={t('User has one or more access keys')}
240	              actionLinks={
241	                <AlertActionLink
242	                  onClick={onDeleteAccessKeys}
243	                  isDisabled={inProgress}
244	                >
245	                  {t('Delete access keys')}
246	                </AlertActionLink>
247	              }
248	            >
249	              <Text>
250	                {t('IAM user has {{count}} access keys', {
251	                  count: iamAccessKeys.length,
252	                })}
253	              </Text>
254	              <List component="ol" className="pf-v6-u-mt-sm">
255	                {iamAccessKeys.map(
256	                  (accessKey) =>
257	                    accessKey.Status === AccessKeyStatus.ACTIVE && (
258	                      <ListItem key={accessKey.AccessKeyId}>
259	                        {accessKey.AccessKeyId}
260	                      </ListItem>
261	                    )
262	                )}
263	              </List>
264	              <Text className="pf-v6-u-mt-md">
265	                <b>
266	                  {t(
267	                    'You must delete the access keys before deleting this user'
268	                  )}
269	                </b>
270	              </Text>
271	            </Alert>
272	          </FlexItem>
273	        )
274	      )}
275	      {deleteSuccess && (
276	        <Alert
277	          variant={AlertVariant.success}
278	          isInline
279	          title={t('Access keys deleted successfully')}
280	          className="co-alert pf-v6-u-mb-md"
281	        >
282	          <p>{t('All access keys assigned to the user have been deleted')}</p>
283	        </Alert>
284	      )}
285	      <FormGroup
286	        label={getTextInputLabel(t)}
287	        className="pf-v6-u-mt-lg pf-v6-u-mb-sm"
288	        fieldId="delete-user"
289	      >
290	        <TextInput
291	          value={deleteText}
292	          id="delete-user"
293	          onChange={(_event, value) => setDeleteText(value)}
294	          type={TextInputTypes.text}
295	          placeholder={t('delete')}
296	        />
297	      </FormGroup>
298	    </Modal>
299	  );
300	};

